		deployResult.stdout || deployResult.stderr,
	);
	if (previewUrl) {
		report.previewUrl = previewUrl;
	}

	appliedChanges.push({
		step: TARGET_COMMAND,
		status: "applied",
		detail: previewUrl
			? `Preview deploy completed: ${previewUrl}`
			: "Preview deploy completed.",
		wrote: true,
